mapper.select:
SELECT menu_Id FROM MENUS
WHERE menuName = #{menuName} AND menuCategory_Id = #{menuCategoryId}
ORDER BY menu_Id DESC

mapper.update:
UPDATE FOODM f
SET f.foodMaterialCountAll = f.foodMaterialCountAll - (
    SELECT SUM(u.usedCount) * #{saleCount}
    FROM USED u
    WHERE u.foodMaterial_Id = f.foodMaterial_Id
      AND u.menu_Id = #{menuId}
)
WHERE f.bId = #{bId}
AND EXISTS (
    SELECT 1 FROM USED u
    WHERE u.foodMaterial_Id = f.foodMaterial_Id
      AND u.menu_Id = #{menuId}
)
AND NOT EXISTS (
    SELECT 1
    FROM FOODM f2, (
        SELECT foodMaterial_Id, SUM(usedCount) * #{saleCount} AS needCount
        FROM USED
        WHERE menu_Id = #{menuId}
        GROUP BY foodMaterial_Id
    ) need
    WHERE f2.foodMaterial_Id = need.foodMaterial_Id
      AND f2.bId = #{bId}
      AND f2.foodMaterialCountAll < need.needCount
)

mapper.select:
SELECT COUNT(*) FROM MENUS m
JOIN MENUC mc ON m.menuCategory_Id = mc.menuCategory_Id
WHERE mc.menuCategory = #{menuCategory}
